export interface VerseEntry {
    ref: string;
    text: string;
    insight: string;
    cross: string[];
}

export const VERSES: VerseEntry[] = [
    { ref: "Jeremiah 29:11", text: "'For I know the plans I have for you,' says the LORD. 'They are plans for good and not for disaster, to give you a future and a hope.'", insight: "In the middle of uncertainty, God holds the blueprint of your story — and it is breathtaking. Every sorrow you've walked through was not the end; it was preparation. He is not scrambling to fix your life. He already knows where this leads, and it is beautiful.", cross: ["Romans 8:28", "Psalm 32:8"] },
    { ref: "Philippians 4:13", text: "For I can do everything through Christ, who gives me strength.", insight: "You were never meant to carry this alone. The same power that raised Jesus from the dead lives inside you. Whatever feels impossible today is not too heavy for the One who strengthens you from within.", cross: ["2 Corinthians 12:9", "Isaiah 40:31"] },
    { ref: "Isaiah 41:10", text: "Don't be afraid, for I am with you. Don't be discouraged, for I am your God. I will strengthen you and help you. I will hold you up with my victorious right hand.", insight: "God doesn't say 'fix it yourself and I'll be proud.' He says 'I am already holding you.' Your weakness is never a surprise to Him — it is an invitation for His strength to show in ways you never imagined.", cross: ["Psalm 46:1", "Deuteronomy 31:6"] },
    { ref: "Romans 8:28", text: "And we know that God causes everything to work together for the good of those who love God and are called according to his purpose for them.", insight: "Not some things. Everything. Even the broken pieces, the wrong turns, the painful seasons — God is weaving them into something you will one day call grace. Trust the Weaver even when you can't see the pattern.", cross: ["Genesis 50:20", "Jeremiah 29:11"] },
    { ref: "Psalm 46:1", text: "God is our refuge and strength, always ready to help in times of trouble.", insight: "He is not a God who watches from a distance. He is already running toward you. In your most terrifying moment, He is your shelter — solid, unshakeable, completely present.", cross: ["Nahum 1:7", "Proverbs 18:10"] },
    { ref: "John 3:16", text: "For this is how God loved the world: He gave his one and only Son, so that everyone who believes in him will not perish but have eternal life.", insight: "The cross was not a tragedy — it was love at its most extreme. God didn't send a letter or a prophet this time. He sent Himself. That is how much you are worth to Him.", cross: ["Romans 5:8", "1 John 4:9"] },
    { ref: "Proverbs 3:5-6", text: "Trust in the LORD with all your heart; do not depend on your own understanding. Seek his will in all you do, and he will show you which path to take.", insight: "When you release the grip of your own understanding, God's direction becomes unmistakable. He doesn't hide His path from you — He waits for you to trust Him enough to follow it.", cross: ["Psalm 37:5", "Isaiah 55:8-9"] },
    { ref: "Matthew 11:28", text: "Then Jesus said, 'Come to me, all of you who are weary and carry heavy burdens, and I will give you rest.'", insight: "He doesn't say 'clean yourself up and then come.' He says come as you are — tired, broken, worn out. The rest He gives is not just sleep; it's the deep peace of being completely known and completely loved.", cross: ["Psalm 23:2", "1 Peter 5:7"] },
    { ref: "2 Corinthians 5:17", text: "This means that anyone who belongs to Christ has become a new person. The old life is gone; a new life has begun!", insight: "You are not just a forgiven version of your old self — you are entirely new. God doesn't do touch-ups. He does resurrections. Today is not day one of fixing you; it is day one of the new you.", cross: ["Romans 6:4", "Ezekiel 36:26"] },
    { ref: "Psalm 23:1-3", text: "The LORD is my shepherd; I have all that I need. He lets me rest in green meadows; he leads me beside peaceful streams. He renews my strength.", insight: "A good shepherd doesn't drive the sheep — he leads them. God is not forcing you through life; He is guiding you toward rest, toward still waters, toward renewal. He knows exactly what your soul needs.", cross: ["John 10:11", "Revelation 7:17"] },
    { ref: "Lamentations 3:22-23", text: "The faithful love of the LORD never ends! His mercies never cease. Great is his faithfulness; his mercies begin afresh each morning.", insight: "Yesterday's failures don't follow you into today. When the sun rises, so does God's mercy — brand new, immeasurable, and completely free. You get to start again. Every single day.", cross: ["Psalm 30:5", "Micah 7:18"] },
    { ref: "Isaiah 40:31", text: "But those who trust in the LORD will find new strength. They will soar high on wings like eagles. They will run and not grow weary. They will walk and not faint.", insight: "Waiting on God is not passive — it is an act of profound trust that activates divine energy. He doesn't refuel you; He replaces your strength with His own. That is why it never runs out.", cross: ["Psalm 27:14", "Habakkuk 3:19"] },
    { ref: "Psalm 34:18", text: "The LORD is close to the brokenhearted; he rescues those whose spirits are crushed.", insight: "God doesn't stand at a comfortable distance when your heart breaks. He moves in closer. He is most near to you in your most broken moment — not because of your strength, but because of His love.", cross: ["Psalm 147:3", "Matthew 5:4"] },
    { ref: "Romans 5:8", text: "But God showed his great love for us by sending Christ to die for us while we were still sinners.", insight: "He didn't wait for you to get better before loving you. He loved you at your absolute worst. That love is not based on your performance — it is rooted in His character, and His character never changes.", cross: ["John 15:13", "Ephesians 2:4-5"] },
    { ref: "1 Corinthians 13:4-5", text: "Love is patient and kind. Love is not jealous or boastful or proud or rude. It does not demand its own way. It is not irritable, and it keeps no record of being wronged.", insight: "This is not just how we should love — it is how God loves us. He keeps no record of your wrongs. Every mistake you've ever made has been erased from His record. That is scandalously good news.", cross: ["Psalm 103:12", "Micah 7:19"] },
    { ref: "Ephesians 2:10", text: "For we are God's masterpiece. He has created us anew in Christ Jesus, so we can do the good things he planned for us long ago.", insight: "You are not an accident or an afterthought — you are God's masterpiece. He crafted you with intention, breathed purpose into you, and placed you exactly where you are on purpose. Your life is not random.", cross: ["Psalm 139:14", "Jeremiah 1:5"] },
    { ref: "Philippians 4:6-7", text: "Don't worry about anything; instead, pray about everything. Tell God what you need, and thank him for all he has done. Then you will experience God's peace, which exceeds anything we can understand.", insight: "Prayer doesn't change your circumstance immediately — it changes you. When you hand your worry to God in prayer, He replaces it with a peace that logic cannot explain. It is supernatural calm in the middle of chaos.", cross: ["1 Peter 5:7", "Isaiah 26:3"] },
    { ref: "Psalm 139:14", text: "Thank you for making me so wonderfully complex! Your workmanship is marvelous — how well I know it.", insight: "God did not mass-produce you. He designed every detail — your laugh, your mind, the way you love. You are not too much or too little. You are exactly what He intended when He said 'wonderful.'", cross: ["Genesis 1:31", "Ephesians 2:10"] },
    { ref: "Joshua 1:9", text: "This is my command — be strong and courageous! Do not be afraid or discouraged. For the LORD your God is with you wherever you go.", insight: "Courage is not the absence of fear — it is taking the step anyway because you know who walks beside you. God doesn't ask you to be fearless. He asks you to trust that He is bigger than what frightens you.", cross: ["Deuteronomy 31:6", "Isaiah 41:10"] },
    { ref: "Psalm 37:4", text: "Take delight in the LORD, and he will give you your heart's desires.", insight: "When God becomes your greatest joy, your desires begin to align with His — and suddenly, fulfillment is no longer something you chase. It is something you live. Delight in Him first, and watch everything shift.", cross: ["Matthew 6:33", "Psalm 27:4"] },
    { ref: "John 14:27", text: "I am leaving you with a gift — peace of mind and heart. And the peace I give is a gift the world cannot give. So don't be troubled or afraid.", insight: "The world offers peace through circumstances — God offers peace in the middle of them. What Jesus gives is not fragile. It doesn't crumble when life does. It holds you steady when everything else is shaking.", cross: ["Philippians 4:7", "Romans 5:1"] },
    { ref: "Psalm 27:1", text: "The LORD is my light and my salvation — so why should I be afraid? The LORD is my fortress, protecting me from danger, so why should I tremble?", insight: "When God is your light, darkness loses its power to terrify you. He is not just a flashlight for the dark moments — He is the sun. In Him, there is no darkness at all.", cross: ["John 8:12", "Isaiah 60:20"] },
    { ref: "Hebrews 11:1", text: "Faith shows the reality of what we hope for; it is the evidence of things we cannot see.", insight: "Faith is not wishful thinking — it is sight for what has not yet appeared. When you trust God's promises, you are not being naive. You are seeing reality more clearly than your eyes ever could.", cross: ["Romans 4:18", "2 Corinthians 4:18"] },
    { ref: "Romans 15:13", text: "I pray that God, the source of hope, will fill you completely with joy and peace because you trust in him. Then you will overflow with confident hope through the power of the Holy Spirit.", insight: "God doesn't ration hope. He fills you completely and then makes you overflow — so that your hope spills out and lifts the people around you. You were never meant to just survive. You were meant to overflow.", cross: ["Psalm 62:5", "1 Peter 1:3"] },
    { ref: "Matthew 5:4", text: "God blesses those who mourn, for they will be comforted.", insight: "Grief is not a spiritual failure. Even Jesus wept. In your sorrow, God draws near with a tenderness that surpasses understanding. The mourner is not abandoned — they are held by the God of all comfort.", cross: ["Psalm 34:18", "2 Corinthians 1:3-4"] },
    { ref: "2 Chronicles 7:14", text: "Then if my people who are called by my name will humble themselves and pray and seek my face and turn from their wicked ways, I will hear from heaven and will forgive their sins and restore their land.", insight: "Revival always begins with humility, not programs. When God's people stop performing and start seeking His face with genuine hearts, He always responds — with forgiveness, with healing, with restoration.", cross: ["James 4:10", "Psalm 51:10"] },
    { ref: "Psalm 103:12", text: "He has removed our sins as far from us as the east is from the west.", insight: "East and west never meet. That is how far God has removed your guilt. Not hidden — removed. Not on probation — gone. He doesn't keep bringing it up because it no longer exists in His records.", cross: ["Isaiah 43:25", "Micah 7:19"] },
    { ref: "2 Corinthians 12:9", text: "Each time he said, 'My grace is all you need. My power works best in weakness.' So now I am glad to boast about my weaknesses, so that the power of Christ can work through me.", insight: "The places you feel most unqualified are the places God's power shines most brilliantly. Your weakness is not an obstacle to His glory — it is the canvas He prefers to paint on.", cross: ["1 Corinthians 1:27", "Philippians 4:13"] },
    { ref: "Zephaniah 3:17", text: "For the LORD your God is living among you. He is a mighty savior. He will take delight in you with gladness. With his love, he will calm all your fears. He will rejoice over you with joyful songs.", insight: "God is not just tolerating you — He is singing over you. Picture the Creator of the universe, standing over your life, singing with joy because of you. You are not a burden. You are His delight.", cross: ["Psalm 149:4", "Isaiah 62:5"] },
    { ref: "Psalm 121:1-2", text: "I look up to the mountains — does my help come from there? My help comes from the LORD, who made heaven and earth!", insight: "When you face a mountain, you don't have to figure out how to climb it. You lift your eyes to the One who made it — and Who made you. The Creator of all things is personally invested in your breakthrough.", cross: ["Psalm 46:1", "Isaiah 41:10"] },
    { ref: "John 15:5", text: "Yes, I am the vine; you are the branches. Those who remain in me, and I in them, will produce much fruit. For apart from me you can do nothing.", insight: "Fruitfulness is not about trying harder — it is about staying connected. The branch doesn't strain to produce fruit; it simply stays attached to the vine. Rest in Him and let the fruit grow naturally.", cross: ["Psalm 1:3", "Galatians 5:22-23"] },
    { ref: "Revelation 21:4", text: "He will wipe every tear from their eyes, and there will be no more death or sorrow or crying or pain. All these things are gone forever.", insight: "Every tear you've ever cried has been seen by God. And He has promised a day when He personally wipes them all away — not just comforts you, but removes the very source of all pain. That day is coming.", cross: ["Isaiah 25:8", "Romans 8:18"] },
    { ref: "Psalm 91:1-2", text: "Those who live in the shelter of the Most High will find rest in the shadow of the Almighty. This I declare about the LORD: He alone is my refuge, my place of safety; he is my God, and I trust him.", insight: "The shadow of the Almighty is not darkness — it is the coolness of His protective presence over your life. To dwell there is a choice to stay close. Stay close today.", cross: ["Psalm 46:1", "Proverbs 18:10"] },
    { ref: "1 John 4:18", text: "Such love has no fear, because perfect love expels all fear. If we are afraid, it is for fear of punishment, and this shows that we have not fully experienced his perfect love.", insight: "Perfect love is the cure for fear — not willpower, not positive thinking. When you encounter how fully God loves you, the fear that once controlled you finds no foothold. Love drives it out completely.", cross: ["Romans 8:15", "Isaiah 43:1"] },
    { ref: "Psalm 28:7", text: "The LORD is my strength and shield. I trust him with all my heart. He helps me, and my heart is filled with joy. I burst out in songs of praise.", insight: "When God is your shield, you don't face the battle unprotected. He stands between you and what would destroy you. Trust that protection today — and let the relief of it become a song.", cross: ["Psalm 18:2", "Exodus 15:2"] },
    { ref: "Isaiah 43:2", text: "When you go through deep waters, I will be with you. When you go through rivers of difficulty, you will not drown. When you walk through the fire of oppression, you will not be burned up; the flames will not consume you.", insight: "He doesn't promise to keep you out of the water — He promises to be there in it with you. The fire didn't consume Shadrach, Meshach, and Abednego. And it will not consume you. God is in there too.", cross: ["Psalm 66:12", "Daniel 3:25"] },
    { ref: "Colossians 3:23", text: "Work willingly at whatever you do, as though you were working for the Lord rather than for people.", insight: "When you shift your audience from people to God, everything changes. The mundane becomes meaningful. The overlooked task becomes worship. God sees every faithful act done in His name, however small.", cross: ["1 Corinthians 10:31", "Ephesians 6:7"] },
    { ref: "Psalm 16:11", text: "You will show me the way of life, granting me the joy of your presence and the pleasures of living with you forever.", insight: "Joy is not found at the end of your to-do list. It is found in God's presence — and that presence is available to you right now, today, in this moment. The path to fullness of life runs directly through Him.", cross: ["John 15:11", "Acts 2:28"] },
    { ref: "Galatians 5:22-23", text: "But the Holy Spirit produces this kind of fruit in our life: love, joy, peace, patience, kindness, goodness, faithfulness, gentleness, and self-control.", insight: "You cannot manufacture these qualities through effort — they are the natural overflow of the Spirit living in you. The question is not 'how do I try harder?' but 'am I staying close to the Source?'", cross: ["John 15:5", "Romans 8:9"] },
    { ref: "Psalm 55:22", text: "Give your burdens to the LORD, and he will take care of you. He will not permit the godly to slip and fall.", insight: "God is not asking you to handle this differently — He is asking you to hand it over entirely. There is a profound difference between managing your burden and releasing it to the One who never stumbles.", cross: ["1 Peter 5:7", "Matthew 11:28"] },
    { ref: "Habakkuk 3:19", text: "The Sovereign LORD is my strength! He makes me as surefooted as a deer, able to tread upon the heights.", insight: "Even the places that seem too high, too steep, too dangerous — God equips you to walk there. You are not climbing alone. He is the one who steadies your feet and lifts you to places you never thought you could reach.", cross: ["Psalm 18:33", "Isaiah 40:31"] },
    { ref: "Nahum 1:7", text: "The LORD is good, a strong refuge when trouble comes. He is close to those who trust in him.", insight: "Don't wait for the storm to pass before you run to God. He is the refuge you run to in the storm. His goodness is not a reward for good behavior — it is His unshakeable nature, available to you right now.", cross: ["Psalm 34:8", "1 Peter 5:7"] },
    { ref: "James 1:2-3", text: "Dear brothers and sisters, when troubles of any kind come your way, consider it an opportunity for great joy. For you know that when your faith is tested, your endurance has a chance to grow.", insight: "God doesn't waste your trials. He is using them to build something in you that ease and comfort never could. The hard season is not a detour from your purpose — it is part of it.", cross: ["Romans 5:3-4", "1 Peter 1:6-7"] },
    { ref: "Matthew 6:33", text: "Seek the Kingdom of God above all else, and live righteously, and he will give you everything you need.", insight: "God doesn't want to be your last resort. He wants to be your first pursuit. When He becomes your primary aim, you discover that He was already the answer to everything else you were looking for.", cross: ["Psalm 37:4", "Luke 12:31"] },
    { ref: "Psalm 40:2", text: "He lifted me out of the pit of despair, out of the mud and the mire. He set my feet on solid ground and steadied me as I walked along.", insight: "He came for you in the pit. Not after you climbed out — while you were still in it. That is who God is. He reaches down into your lowest places and lifts you to standing. That is grace.", cross: ["Psalm 18:16", "Isaiah 61:3"] },
    { ref: "Romans 8:38-39", text: "And I am convinced that nothing can ever separate us from God's love. Neither death nor life, neither angels nor demons, neither our fears for today nor our worries about tomorrow — not even the powers of hell can separate us from God's love.", insight: "Read that list again. Nothing. Not your worst failure. Not your greatest fear. Not the darkness of your past. Not the uncertainty of your future. God's love has no escape clause. You are held. Permanently.", cross: ["John 10:28", "Psalm 139:7-10"] },
    { ref: "1 Peter 5:7", text: "Give all your worries and cares to God, for he cares about you.", insight: "This is not a suggestion to try harder at not worrying. It's an invitation to release. To open your hands and let God take what you were never meant to carry. He cares. That's not poetry — it's a personal promise to you.", cross: ["Philippians 4:6", "Matthew 11:28"] },
    { ref: "Psalm 62:5-6", text: "Let all that I am wait quietly before God, for my hope is in him. He alone is my rock and my salvation, my fortress where I will not be shaken.", insight: "In a world screaming for your attention, silence before God is an act of defiance — and trust. When you wait on Him, you are saying 'You are enough.' And He always proves it.", cross: ["Isaiah 30:15", "Lamentations 3:26"] },
    { ref: "Ephesians 3:20", text: "Now all glory to God, who is able, through his mighty power at work within us, to accomplish infinitely more than we might ask or think.", insight: "Your biggest dream is too small for God. What you're hoping for in prayer is not the ceiling of what He can do — it's barely the floor. He accomplishes the unimaginable through ordinary, surrendered people.", cross: ["1 Corinthians 2:9", "Jeremiah 33:3"] },
    { ref: "Psalm 30:5", text: "For his anger lasts only a moment, but his favor lasts a lifetime! Weeping may last through the night, but joy comes with the morning.", insight: "The night of weeping is real — but it is not permanent. Morning always comes. Every dark season has a sunrise built in by God. Your crying is heard. Your joy is coming.", cross: ["Lamentations 3:22-23", "Psalm 126:5"] },
    { ref: "Deuteronomy 31:6", text: "So be strong and courageous! Do not be afraid and do not panic before them. For the LORD your God will personally go ahead of you. He will neither fail you nor abandon you.", insight: "He goes ahead of you. Before you face the day, God is already there — in your meeting, your conversation, your hardest moment. You are never walking into anything He hasn't already prepared and preceded.", cross: ["Joshua 1:9", "Isaiah 52:12"] },
    { ref: "John 10:10", text: "The thief's purpose is to steal and kill and destroy. My purpose is to give them a rich and satisfying life.", insight: "Jesus didn't come to give you a life of just getting by. He came to give you abundant life — rich, meaningful, full. The enemy wants you to believe you're barely surviving. Jesus says you were made to thrive.", cross: ["John 6:35", "Psalm 36:8"] },
    { ref: "Isaiah 26:3", text: "You will keep in perfect peace all who trust in you, all whose thoughts are fixed on you!", insight: "Peace is not the absence of problems — it is the presence of God in your mind. When you deliberately anchor your thoughts on Him, He guards your mind with a peace that surpasses your circumstances.", cross: ["Philippians 4:7", "John 14:27"] },
    { ref: "Psalm 25:4-5", text: "Show me the right path, O LORD; point out the road for me to follow. Lead me by your truth and teach me, for you are the God who saves me. All day long I put my hope in you.", insight: "Asking God for direction is not weakness — it is wisdom. He delights in guiding those who long to walk in step with Him. Your posture of dependence is exactly where His guidance flows.", cross: ["Proverbs 3:5-6", "Psalm 32:8"] },
    { ref: "Genesis 28:15", text: "What's more, I am with you, and I will protect you wherever you go. One day I will bring you back to this land. I will not leave you until I have finished giving you everything I have promised you.", insight: "Whatever God has promised you, He will finish. He does not start a story and leave it unfinished. His promises are not inspirational words — they are commitments He has staked His character on.", cross: ["Philippians 1:6", "Numbers 23:19"] },
    { ref: "Psalm 147:3", text: "He heals the brokenhearted and bandages their wounds.", insight: "God is the Great Physician of your soul. He doesn't look at your broken heart and suggest you 'just get over it.' He kneels down, tends to your wounds with tenderness, and heals what only He can reach.", cross: ["Psalm 34:18", "Luke 4:18"] },
    { ref: "Psalm 119:105", text: "Your word is a lamp to guide my feet and a light for my path.", insight: "You don't need to see the entire road — just the next step. God's Word illuminates exactly what you need for the moment you're in. Step by faithful step, He lights the way forward.", cross: ["Psalm 43:3", "Proverbs 6:23"] },
    { ref: "Micah 6:8", text: "No, O people, the LORD has told you what is good, and this is what he requires of you: to do what is right, to love mercy, and to walk humbly with your God.", insight: "The Christian life is not complicated — it's costly. Justice, mercy, humility. Not programs, not platforms. God is looking for people whose daily walk reflects His heart. Simple, but transformative.", cross: ["Matthew 23:23", "James 2:14"] },
    { ref: "2 Timothy 1:7", text: "For God has not given us a spirit of fear and timidity, but of power, love, and self-discipline.", insight: "Fear is not from God — and that means every fearful thought that has ever paralyzed you has an opponent. Power. Love. Self-discipline. These are the actual gifts God has placed inside you. Walk in them today.", cross: ["Romans 8:15", "1 John 4:18"] },
    { ref: "Lamentations 3:25-26", text: "The LORD is good to those who depend on him, to those who search for him. So it is good to wait quietly for salvation from the LORD.", insight: "Waiting is not doing nothing. Waiting on God is an act of faith — it says 'I believe He is moving even when I cannot see it.' The quiet wait is where your trust deepens into something unshakeable.", cross: ["Isaiah 40:31", "Psalm 62:5"] },
    { ref: "Psalm 73:26", text: "My health may fail, and my spirit may grow weak, but God remains the strength of my heart; he is mine forever.", insight: "When your own strength gives out — and it will — you discover the strength that was always there. God doesn't just give you strength; He becomes your strength. And that kind of strength never exhausts itself.", cross: ["2 Corinthians 12:9", "Isaiah 41:10"] },
    { ref: "Hebrews 4:16", text: "So let us come boldly to the throne of our gracious God. There we will receive his mercy, and we will find grace to help us when we need it most.", insight: "You are not approaching a court of condemnation — you are walking up to a throne of grace. You are welcomed. You are heard. You are helped. Come boldly. He is waiting for you there.", cross: ["James 4:8", "Ephesians 3:12"] },
    { ref: "Matthew 5:6", text: "God blesses those who hunger and thirst for justice, for they will be satisfied.", insight: "Longing for more of God is never wasted desire. That hunger you feel — for meaning, for righteousness, for His presence — He put it there. And He always, always satisfies the ones who come seeking.", cross: ["Psalm 63:1", "John 6:35"] },
    { ref: "Psalm 84:11", text: "For the LORD God is our sun and our shield. He gives us grace and glory. The LORD will withhold no good thing from those who do what is right.", insight: "God is not a reluctant giver. He withholds nothing good from those who walk with Him. Every good thing in your life finds its source in Him — and there is so much more He is ready to give.", cross: ["James 1:17", "Matthew 7:11"] },
    { ref: "Romans 12:12", text: "Rejoice in our confident hope. Be patient in trouble, and keep on praying.", insight: "Three habits that carry you through anything: hope, patience, prayer. Not talent, not circumstances, not good luck. These three practiced daily become the foundation that holds when everything else shifts.", cross: ["1 Thessalonians 5:16-18", "Psalm 40:1"] },
    { ref: "Psalm 143:8", text: "Let me hear of your unfailing love each morning, for I am trusting you. Show me where to walk, for I give myself to you.", insight: "Start every day with God's love as your first filter. Before the news, before the noise — His unfailing love. When that is your morning foundation, the day looks entirely different.", cross: ["Lamentations 3:22-23", "Psalm 90:14"] },
    { ref: "Ephesians 1:4-5", text: "Even before he made the world, God loved us and chose us in Christ to be holy and without fault in his eyes. God decided in advance to adopt us into his own family by bringing us to himself through Jesus Christ.", insight: "You were chosen before you were born. God's love for you is not reactive — it is eternal. He didn't find you and then decide to love you. He loved you before time began.", cross: ["John 15:16", "Romans 8:29"] },
    { ref: "Psalm 84:2", text: "I long, yes, I faint with longing to enter the courts of the LORD. With my whole being, body and soul, I will shout joyfully to the living God.", insight: "This is the posture that changes everything — a soul that aches for God's presence more than any other comfort. When He becomes the longing of your heart, you discover He was also the answer all along.", cross: ["Psalm 42:1-2", "Matthew 5:8"] },
    { ref: "Numbers 6:24-26", text: "'May the LORD bless you and protect you. May the LORD smile on you and be gracious to you. May the LORD show you his favor and give you his peace.'", insight: "This is God's wish for you — blessing, protection, grace, favor, peace. Not your minimum survival, but His maximum blessing. Receive this over your life today as a prayer that the Author of peace is already answering.", cross: ["John 14:27", "Romans 15:13"] },
    { ref: "Psalm 36:7", text: "How precious is your unfailing love, O God! All humanity finds shelter in the shadow of your wings.", insight: "The shelter of God's wings is open to every single person — no credentials required. His love is not selective, not earned, not fragile. It is unfailing, and it is offered to you freely and fully today.", cross: ["Psalm 91:4", "Ruth 2:12"] },
    { ref: "Hebrews 13:5", text: "For God has said, 'I will never fail you. I will never abandon you.'", insight: "You have never been left alone — not even in the moments that felt most empty. God's presence doesn't depend on your awareness of it. He said never, and He means it. You are not abandoned.", cross: ["Deuteronomy 31:6", "Psalm 27:10"] },
    { ref: "Psalm 31:24", text: "So be strong and courageous, all you who put your hope in the LORD!", insight: "Hope in God is not wishful thinking — it is the most rational act in existence. You are putting your confidence in the only One who has never failed, never abandoned, and never broken a single promise.", cross: ["Joshua 1:9", "Romans 15:13"] },
    { ref: "Isaiah 55:8-9", text: "'My thoughts are nothing like your thoughts,' says the LORD. 'And my ways are far beyond anything you could imagine. For just as the heavens are higher than the earth, so my ways are higher than your ways and my thoughts higher than your thoughts.'", insight: "When you can't understand what God is doing, it's not because He's absent — it's because He's operating at a level your mind hasn't yet reached. Trust the One whose perspective is infinitely higher than yours.", cross: ["Proverbs 3:5-6", "Romans 11:33"] },
    { ref: "Micah 7:18-19", text: "Where is another God like you, who pardons the guilt of the remnant, overlooking the sins of his special people? You will not stay angry with your people forever, because you delight in showing unfailing love. Once again you will have compassion on us. You will trample our sins under your feet and throw them into the depths of the ocean!", insight: "God doesn't just forgive — He celebrates it. He delights in showing mercy. Your sins are not just forgiven; they are drowned in an ocean. He is not keeping score. He already chose to lose count.", cross: ["Psalm 103:12", "Romans 8:1"] },
    { ref: "Philippians 1:6", text: "And I am certain that God, who began the good work within you, will continue his work until it is finally finished on the day when Christ Jesus returns.", insight: "God finishes what He starts. The transformation you're in the middle of right now is not abandoned — it is ongoing. He is still working. He will not walk away from His own masterpiece incomplete.", cross: ["Genesis 28:15", "Hebrews 12:2"] },
    { ref: "Psalm 126:5-6", text: "Those who plant in tears will harvest with shouts of joy. They weep as they go to plant their seed, but they sing as they return with the harvest.", insight: "Some things you plant in tears. You do the right thing, the faith-filled thing, in the middle of heartbreak — and you trust the harvest to God. He always honors seeds planted in faithfulness, no matter the season.", cross: ["Galatians 6:9", "Isaiah 61:3"] },
    { ref: "Romans 8:1", text: "So now there is no condemnation for those who belong to Christ Jesus.", insight: "No condemnation. Not reduced condemnation. Not probationary freedom. None. The verdict over your life, spoken by the highest court in the universe, is: not guilty. Beloved. Free. Fully forgiven.", cross: ["John 3:17", "Romans 8:38-39"] },
    { ref: "Isaiah 40:28-29", text: "Have you never heard? Have you never understood? The LORD is the everlasting God, the Creator of all the earth. He never grows weak or weary. No one can measure the depths of his understanding. He gives power to the weak and strength to the powerless.", insight: "The God who holds galaxies together is the same God who holds you together. He does not run low. He never clocks out. His energy toward your life is inexhaustible. Let that truth still your anxious heart.", cross: ["Isaiah 40:31", "Psalm 121:4"] },
    { ref: "1 John 3:1", text: "See how very much our Father loves us, for he calls us his children, and that is what we are!", insight: "You don't have to earn the title — you already have it. Child of God. Not employee, not visitor, not stranger. Child. And a Father's love for His child is the fiercest, most committed love that exists.", cross: ["John 1:12", "Ephesians 1:5"] },
    { ref: "Psalm 145:18", text: "The LORD is close to all who call on him, yes, to all who call on him in truth.", insight: "Proximity to God is triggered by one thing: calling on Him. Not performance, not a certain prayer formula — just honest, truthful reaching toward Him. He is already leaning in. He hears you.", cross: ["James 4:8", "Psalm 34:18"] },
    { ref: "Matthew 5:8", text: "God blesses those whose hearts are pure, for they will see God.", insight: "Purity of heart is not about perfection — it is about undivided desire. When your heart singularly wants God above everything else, you begin to see Him everywhere. In beauty, in sorrow, in ordinary moments.", cross: ["Psalm 24:4", "Hebrews 12:14"] },
    { ref: "Galatians 6:9", text: "So let's not get tired of doing good. At just the right time we will reap a harvest of blessing if we don't give up.", insight: "The temptation to quit always comes before the breakthrough. Keep going. Keep loving, serving, trusting — not because you see results, but because God sees every faithful act and the harvest is always coming.", cross: ["Psalm 126:5-6", "Hebrews 10:36"] },
    { ref: "Psalm 4:8", text: "In peace I will lie down and sleep, for you alone, O LORD, will keep me safe.", insight: "When God is your security system, you can actually rest. Not just sleep — rest. The kind that comes when you know someone completely trustworthy is standing guard. He never sleeps. You can.", cross: ["Proverbs 3:24", "Psalm 127:2"] },
    { ref: "Ezekiel 36:26", text: "And I will give you a new heart, and I will put a new spirit in you. I will take out your stony, stubborn heart and give you a tender, responsive heart.", insight: "God doesn't renovate the old heart. He replaces it. All the hardness, bitterness, and pain — He removes it and gives you something entirely new. You are not stuck. Your heart can change. He promises it.", cross: ["2 Corinthians 5:17", "Psalm 51:10"] },
    { ref: "Psalm 9:10", text: "Those who know your name trust in you, for you, O LORD, do not abandon those who search for you.", insight: "The more you know God — His character, His faithfulness, His love — the more naturally you trust Him. Faith is not a leap into the unknown. It is a step toward the most trustworthy One who exists.", cross: ["Jeremiah 29:13", "Proverbs 18:10"] },
    { ref: "Luke 15:20", text: "So he returned home to his father. And while he was still a long way off, his father saw him coming. Filled with love and compassion, he ran to his son, embraced him, and kissed him.", insight: "God doesn't wait for you to reach the door before He runs to meet you. The moment you turn toward Him — just begin to return — He is already running. Arms open. That is not a parable. That is God's heart for you.", cross: ["Psalm 103:13", "Romans 5:8"] },
    { ref: "Hebrews 12:1", text: "Therefore, since we are surrounded by such a huge crowd of witnesses, let us strip off every weight that slows us down, especially the sin that so easily trips us up. And let us run with endurance the race God has set before us.", insight: "You are not running alone. A great cloud of those who've gone before you is cheering you on. And God Himself has designed a specific, beautiful race just for you. Run your race — not someone else's.", cross: ["1 Corinthians 9:24", "2 Timothy 4:7"] },
    { ref: "John 16:33", text: "I have told you all this so that you may have peace in me. Here on earth you will have many trials and sorrows. But take heart, because I have overcome the world.", insight: "He was honest about the hardship and victorious about the outcome. Trials are real. Pain is real. But so is the One who already conquered everything you're facing. Take heart — the battle belongs to Him.", cross: ["Romans 8:37", "1 John 5:4"] },
    { ref: "Psalm 18:2", text: "The LORD is my rock, my fortress, and my savior; my God is my rock, in whom I find protection. He is my shield, the power that saves me, and my place of safety.", insight: "When everything feels unstable — relationships, finances, health — God is the one thing that does not move. He is not shaken by what shakes you. Stand on Him today.", cross: ["Matthew 7:24", "1 Corinthians 10:4"] },
    { ref: "Revelation 3:20", text: "'Look! I stand at the door and knock. If you hear my voice and open the door, I will come in, and we will share a meal together as friends.'", insight: "He is not forcing His way in. He knocks — patiently, persistently, lovingly. The invitation is always open. Open the door today. Not tomorrow, not after you've cleaned everything up. Today. He wants to come in.", cross: ["James 4:8", "Song of Songs 5:2"] },
    { ref: "Psalm 37:23-24", text: "The LORD directs the steps of the godly. He delights in every detail of their lives. Though they stumble, they will never fall, for the LORD holds them by the hand.", insight: "God is not just interested in the big moments of your life. He delights in every detail — your ordinary Tuesday, your small choices, your quiet faithfulness. He holds your hand through all of it.", cross: ["Psalm 25:9", "Proverbs 20:24"] },
    { ref: "Matthew 19:26", text: "Jesus looked at them intently and said, 'Humanly speaking, it is impossible. But with God everything is possible.'", insight: "The situation labeled 'impossible' by every logical measure is still within the territory of God's ability. He specializes in precisely the things that humanity has given up on. Don't give up. God hasn't.", cross: ["Luke 1:37", "Jeremiah 32:27"] },
    { ref: "Psalm 51:10", text: "Create in me a clean heart, O God. Renew a loyal spirit within me.", insight: "This is one of the most powerful prayers in Scripture — raw, honest, completely dependent on God. You don't have to fix yourself before praying it. The brokenness in the prayer is exactly what God is responding to.", cross: ["Ezekiel 36:26", "2 Corinthians 5:17"] },
    { ref: "Isaiah 61:3", text: "To all who mourn in Israel, he will give a crown of beauty for ashes, a joyous blessing instead of mourning, festive praise instead of despair.", insight: "God is in the business of exchanging your worst for His best. Ashes become a crown. Mourning becomes joy. Despair becomes praise. He is the God of the beautiful reversal — and He has not finished with your story.", cross: ["Psalm 30:11", "Joel 2:25"] },
    { ref: "Psalm 46:10", text: "'Be still, and know that I am God! I will be honored by every nation. I will be honored throughout the world.'", insight: "Be still. Not forever — just now. Stop striving long enough to remember who is God and who is not. In the stillness, you remember He is in control. And that changes everything about how you face the day.", cross: ["Exodus 14:14", "Lamentations 3:26"] },
    { ref: "1 Chronicles 16:34", text: "Give thanks to the LORD, for he is good! His faithful love endures forever.", insight: "Gratitude is not denial of pain — it is choosing to see God's goodness alongside it. His love enduring forever means it outlasts every trial, every failure, every fear. It has not ended. It will not end.", cross: ["Psalm 107:1", "Lamentations 3:22-23"] },
    { ref: "Hebrews 10:23", text: "Let us hold tightly without wavering to the hope we affirm, for God can be trusted to keep his promise.", insight: "Your grip on God may waver — but His grip on His promise never does. Hold on to hope not because you're strong, but because what you're holding to is stronger than anything that could pull you away.", cross: ["Numbers 23:19", "1 Corinthians 1:9"] },
    { ref: "Psalm 32:7-8", text: "For you are my hiding place; you protect me from trouble. You surround me with songs of victory. The LORD says, 'I will guide you along the best pathway for your life. I will advise you and watch over you.'", insight: "The best pathway is not necessarily the easiest — but it is the one God watches over personally. He doesn't just give directions from a distance; He walks the path right beside you.", cross: ["Isaiah 30:21", "Psalm 48:14"] },
    { ref: "Malachi 3:10", text: "'Bring all the tithes into the storehouse so there will be enough food in my Temple. If you do,' says the LORD of Heaven's Armies, 'I will open the windows of heaven for you. I will pour out a blessing so great you won't have enough room to take it in!'", insight: "God dares you to test His generosity. His economy is upside-down from the world's — the more you release, the more He pours. Generosity is not the loss of something; it is the opening of a window.", cross: ["Luke 6:38", "2 Corinthians 9:8"] },
    { ref: "Jeremiah 31:3", text: "Long ago the LORD said to Israel: 'I have loved you, my people, with an everlasting love. With unfailing love I have drawn you to myself.'", insight: "God's love for you stretches back before your birth and extends forward past your last breath. It is not a feeling that rises and falls with circumstances. It is everlasting — and it is pulling you toward Him right now.", cross: ["Romans 8:38-39", "John 6:44"] },
    { ref: "Romans 8:11", text: "The Spirit of God, who raised Jesus from the dead, lives in you. And just as God raised Christ Jesus from the dead, he will give life to your mortal bodies by this same Spirit living within you.", insight: "The same divine energy that defeated death is alive inside you. You are not facing your day in your own strength. The resurrection power of God is your inheritance. Whatever feels dead can live again.", cross: ["Ephesians 1:19-20", "John 14:17"] },
    { ref: "Psalm 84:5", text: "What joy for those whose strength comes from the LORD, who have set their minds on a pilgrimage to God.", insight: "When your mind is set on the things of God — on seeking Him, on the journey toward Him — joy follows naturally. Not as a reward for the journey, but as a companion on it.", cross: ["Psalm 16:11", "Isaiah 35:10"] },
    { ref: "Colossians 1:16-17", text: "For through him God created everything in the heavenly realms and on earth... He existed before anything else, and he holds all creation together.", insight: "The God you pray to is the same God holding the atoms of the universe together at this very moment. Nothing is holding itself together — He is. Including you. Including your situation. He is holding it all.", cross: ["Hebrews 1:3", "John 1:3"] },
    { ref: "Psalm 42:8", text: "But each day the LORD pours his unfailing love upon me, and through each night I sing his songs, praying to God who gives me life.", insight: "Every single day, without exception, God pours His unfailing love over you. It is not a random gift — it is a daily, deliberate outpouring. You wake up to love. You sleep under love. You are immersed in it.", cross: ["Lamentations 3:22-23", "Psalm 63:3"] },
    { ref: "2 Peter 1:3", text: "By his divine power, God has given us everything we need for living a godly life. We have received all of this by coming to know him, the one who called us to himself by means of his marvelous glory and excellence.", insight: "'Everything we need' means you are not missing something essential for the life God designed for you. It has already been given. The question is not 'where is it?' — it is 'will you take it?'", cross: ["Ephesians 1:3", "Philippians 4:19"] },
    { ref: "Acts 2:28", text: "You have shown me the way of life, and you will fill me with the joy of your presence.", insight: "The way of life is not a path you discover by accident. It's revealed through relationship with God. And at the end of that path is not just peace or meaning — it is the overwhelming joy of His very presence.", cross: ["Psalm 16:11", "John 15:11"] },
    { ref: "Psalm 20:7", text: "Some nations boast of their chariots and horses, but we boast of the name of the LORD our God.", insight: "What you trust in is revealed by what you boast about. God invites you to boast in the most unbeatable name of all. Not in your resume or your resources — but in the name that makes heaven stop and listen.", cross: ["Proverbs 18:10", "Philippians 3:3"] },
    { ref: "1 Samuel 16:7", text: "But the LORD said to Samuel, 'Don't judge by his appearance or height, for I have rejected him. The LORD doesn't see things the way you see them. People judge by outward appearance, but the LORD looks at the heart.'", insight: "God is never impressed by what impresses people. He bypasses the polished exterior and looks straight into the heart. While the world celebrates the performance, God celebrates the posture of your heart.", cross: ["Matthew 5:8", "Psalm 51:17"] },
    { ref: "Psalm 100:3", text: "Acknowledge that the LORD is God! He made us, and we are his. We are his people, the sheep of his pasture.", insight: "You belong to the One who made you — and He is not an absent Creator. He is your shepherd. Active, present, knowing your name, guiding you personally. You are not just created; you are cared for.", cross: ["John 10:11", "Ezekiel 34:11-12"] },
    { ref: "James 4:8", text: "Come close to God, and God will come close to you.", insight: "This is one of the most beautiful mechanics in all of Scripture. Movement toward God is met with movement from God. You take one step. He takes one step. Draw near and discover how near He already is.", cross: ["Revelation 3:20", "Hebrews 4:16"] },
    { ref: "Luke 1:37", text: "For the word of God will never fail.", insight: "Every single promise God has ever made is backed by His eternal authority and His unchanging character. He has never spoken a word He failed to keep. What He has promised you will come to pass.", cross: ["Numbers 23:19", "Isaiah 55:11"] },
    { ref: "Psalm 107:9", text: "For he satisfies the thirsty and fills the hungry with good things.", insight: "Only God can satisfy the kind of hunger that no food or accomplishment or relationship can reach. He designed that ache in you on purpose — so you would find its fulfillment only in Him. He is ready to fill you.", cross: ["John 6:35", "Psalm 63:1"] },
    { ref: "Romans 8:18", text: "Yet what we suffer now is nothing compared to the glory he will reveal to us later.", insight: "Your suffering is real, but it is not the end of the story. What God has planned as your future makes every present hardship — as real and heavy as it is — seem small by comparison. Keep going.", cross: ["2 Corinthians 4:17", "Revelation 21:4"] },
    { ref: "Psalm 3:3", text: "But you, O LORD, are a shield around me; you are my glory, the one who holds my head high.", insight: "When shame or defeat bows your head, God lifts it. He is the one who restores dignity and honor. He is your glory — not just your protector, but the source of the beauty and worth that defines you.", cross: ["Psalm 41:12", "Luke 15:20"] },
    { ref: "Isaiah 54:10", text: "For the mountains may move and the hills disappear, but even then my faithful love for you will remain. My covenant of blessing will never be broken, says the LORD, who has mercy on you.", insight: "Mountains have moved before. But God's love for you has never moved — not once. It is more stable than the ground you stand on. More certain than tomorrow's sunrise. His love is the absolute constant.", cross: ["Jeremiah 31:3", "Romans 8:38-39"] },
    { ref: "Proverbs 16:9", text: "We can make our plans, but the LORD determines our steps.", insight: "Planning is wisdom. But releasing those plans into God's hands is faith. When you hold your plans loosely, God is free to direct your steps toward something better than what you originally imagined.", cross: ["Psalm 37:23", "Jeremiah 29:11"] },
    { ref: "1 Corinthians 2:9", text: "That is what the Scriptures mean when they say, 'No eye has seen, no ear has heard, and no mind has imagined what God has prepared for those who love him.'", insight: "Your imagination is the ceiling. God's plan for your life has no ceiling. What He has prepared is beyond anything you've dreamed, seen, or heard. All of it is ready for those who love Him.", cross: ["Ephesians 3:20", "Isaiah 64:4"] },
    { ref: "Psalm 71:5", text: "O Lord, you alone are my hope. I've trusted you, O LORD, from childhood.", insight: "Hope placed in God is the only hope that never disappoints. Every earthly hope has a condition and an expiration. God's promises have neither. He is the hope that holds through every season of life.", cross: ["Psalm 62:5", "Romans 5:5"] },
    { ref: "Romans 5:3-5", text: "We can rejoice, too, when we run into problems and trials, for we know that they help us develop endurance. And endurance develops strength of character, and character strengthens our confident hope of salvation. And this hope will not lead to disappointment.", insight: "Hardship is not punishment — it is curriculum. God is developing something in you through this trial that you could not build in comfort. And at the end of the process: unshakeable hope. Hang on.", cross: ["James 1:2-3", "1 Peter 1:6-7"] },
    { ref: "Titus 3:5", text: "He saved us, not because of the righteous things we had done, but because of his mercy. He washed away our sins, giving us a new birth and new life through the Holy Spirit.", insight: "Salvation is the most unfair thing God ever did — in the most beautiful way. You didn't earn it. You couldn't. He gave it out of pure mercy. That is the radical, illogical, staggering love of God for you.", cross: ["Ephesians 2:8-9", "John 3:5"] },
    { ref: "Psalm 119:114", text: "You are my refuge and my shield; your word is my source of hope.", insight: "When the world gives you a thousand reasons to despair, God's Word gives you one reason that outweighs them all — His promises are true. Hide in them. Stand on them. They will not shift beneath you.", cross: ["Psalm 119:105", "Hebrews 11:1"] },
    { ref: "Isaiah 30:21", text: "Your own ears will hear him. Right behind you a voice will say, 'This is the way you should go,' whether to the right or to the left.", insight: "God's guidance is rarely a spotlight from a distance — it's a voice right behind you, personal and close. He is near enough to whisper direction. Stay quiet enough to hear Him when He speaks.", cross: ["Psalm 32:8", "John 10:27"] },
    { ref: "Genesis 1:31", text: "Then God looked over all he had made, and he saw that it was very good!", insight: "God looked at His creation — including you — and called it very good. Not good enough. Not mostly good. Very good. Whatever voice has told you otherwise was not God's voice. He still calls you very good.", cross: ["Psalm 139:14", "Ephesians 2:10"] },
    { ref: "Psalm 5:3", text: "Listen to my voice in the morning, LORD. Each morning I bring my requests to you and wait expectantly.", insight: "Morning prayer is not just a discipline — it is a declaration that God is your starting point each day. When you begin with Him, everything else finds its right place. He is the most important appointment of the day.", cross: ["Psalm 143:8", "Mark 1:35"] },
    { ref: "Ephesians 6:10-11", text: "A final word: Be strong in the Lord and in his mighty power. Put on all of God's armor so that you will be able to stand firm against all strategies of the devil.", insight: "The battle you face is not primarily physical but spiritual — and God has equipped you for it completely. You are not unarmed. You are not outmatched. In His strength, you can stand. Stand firm today.", cross: ["2 Corinthians 10:4", "James 4:7"] },
    { ref: "Psalm 63:3", text: "Your unfailing love is better than life itself; how I praise you!", insight: "Better than life. The psalmist had tasted enough of God's love to make that comparison without hesitation. There is no experience this earth offers that compares to the overwhelming reality of God's love for you.", cross: ["Psalm 84:10", "Philippians 3:8"] },
    { ref: "John 11:35", text: "Then Jesus wept.", insight: "God cries. Jesus, at the tomb of His friend, wept. He was not unmoved by the grief around Him. He is not unmoved by yours. The God of the universe has feelings — and He feels deeply for you in your pain.", cross: ["Psalm 34:18", "Isaiah 53:3"] },
    { ref: "Psalm 33:18", text: "But the LORD watches over those who fear him, those who rely on his unfailing love.", insight: "Being watched over by God is not surveillance — it's care. He is attentive to your life, to your needs, to your worries. You are not unseen. You are not forgotten. God's eyes are on you with love.", cross: ["Psalm 121:2-3", "Nahum 1:7"] },
    { ref: "2 Samuel 22:31", text: "God's way is perfect. All the LORD's promises prove true. He is a shield for all who look to him for protection.", insight: "Perfect. Not mostly right. Not usually reliable. Perfect. Every promise, always kept. Every path He sets, always right. When you don't understand His way, you can trust His character. He is perfect in all He does.", cross: ["Psalm 18:30", "Deuteronomy 32:4"] },
    { ref: "Philippians 4:19", text: "And this same God who takes care of me will supply all your needs from his glorious riches, which have been given to us in Christ Jesus.", insight: "Your needs are not a burden to God — they are an invitation to His provision. And He doesn't give from the edges of His supply. He gives from His glorious riches. There is no shortage in heaven.", cross: ["Matthew 6:31-33", "Psalm 34:9"] },
    { ref: "Psalm 23:4", text: "Even when I walk through the darkest valley, I will not be afraid, for you are close beside me. Your rod and your staff protect and comfort me.", insight: "The darkest valley is not a sign of God's absence — it is, paradoxically, the place where He is most intensely close. The shepherd doesn't abandon the sheep in the valley. He walks right there alongside.", cross: ["Isaiah 43:2", "Psalm 46:1"] },
    { ref: "Joel 2:25", text: "The LORD says, 'I will give you back what you lost to the swarming locusts, the hopping locusts, the stripping locusts, and the cutting locusts.'", insight: "God is in the business of restoration. The years that were taken from you — by pain, by poor choices, by circumstance — are not beyond His ability to redeem. He can give back what the locusts devoured.", cross: ["Isaiah 61:3", "Psalm 126:5-6"] },
    { ref: "Psalm 46:5", text: "God dwells in that city; it cannot be destroyed. From the very break of day, God will protect it.", insight: "What God dwells in cannot ultimately be destroyed. He lives in you. That makes you more resilient than you realize. You may be bending, but you are not broken. From daybreak, He is your protector.", cross: ["John 14:17", "1 Corinthians 3:16"] },
    { ref: "Mark 10:27", text: "Jesus looked at them intently and said, 'Humanly speaking, it is impossible. But not with God. Everything is possible with God.'", insight: "Impossible is a word that applies to human limitations — not to God. Every breakthrough you're waiting for, every prayer you've whispered with fading hope — none of it is beyond Him. Everything is possible with God.", cross: ["Matthew 19:26", "Luke 1:37"] },
    { ref: "Psalm 86:15", text: "But you, O Lord, are a God of compassion and mercy, slow to get angry and filled with unfailing love and faithfulness.", insight: "This is who God is at His core. Not a judge waiting to condemn, not a God quick to punish. Compassionate. Merciful. Patient. Faithful. His first response toward you is love. Always has been. Always will be.", cross: ["Exodus 34:6", "Psalm 103:8"] },
    { ref: "John 14:6", text: "Jesus told him, 'I am the way, the truth, and the life. No one can come to the Father except through me.'", insight: "Jesus doesn't just point the way — He is the way. He doesn't just teach the truth — He is the truth. He doesn't just describe life — He is the source of it. Everything you need is found in the person of Jesus.", cross: ["John 10:9", "Acts 4:12"] },
    { ref: "Psalm 121:3-4", text: "He will not let you stumble; the one who watches over you will not slumber. Indeed, he who watches over Israel never slumbers or sleeps.", insight: "God never takes his eyes off you. Not at 2 AM when you can't sleep. Not in the crisis. Not in the quiet. He is watching — not with suspicion, but with the fierce attentiveness of a Father who loves you completely.", cross: ["Psalm 34:15", "Isaiah 27:3"] },
    { ref: "Hebrews 12:2", text: "We do this by keeping our eyes on Jesus, the champion who initiates and perfects our faith.", insight: "When the circumstances around you are loud and confusing, the single most stabilizing act is fixing your gaze on Jesus. He started this faith journey in you and He will complete it. Look to Him.", cross: ["Philippians 1:6", "Isaiah 26:3"] },
];
